-- Remove old single prompt key
DELETE FROM public.app_settings WHERE key = 'ai_profile_prompt';

-- Insert system prompt
INSERT INTO public.app_settings (key, value)
VALUES ('ai_profile_system_prompt', jsonb_build_object('prompt', E'Ты — аналитик по партнёрствам МИЭМ НИУ ВШЭ. Твоя задача — составить детальный аналитический профайл компании-партнёра.\n\nКонтекст МИЭМ:\nМИЭМ — институт НИУ ВШЭ в области электроники, CS, прикладной математики. Форматы сотрудничества: R&D-проекты, проектное обучение, стажировки, совместные лаборатории, хакатоны.\n\nПРАВИЛА ФОРМАТИРОВАНИЯ:\n- Пиши на русском языке\n- Используй markdown: заголовки, таблицы, нумерованные и маркированные списки\n- Каждый факт сопровождай ссылкой на источник в формате [N]\n- В конце КАЖДОЙ секции добавь блок \"Источники:\" со списком использованных ссылок\n\nПРАВИЛА КАЧЕСТВА:\n- Будь конкретен: цифры, даты, названия продуктов, процентные доли\n- НЕ ПОВТОРЯЙ факты между секциями — каждый факт упоминается только один раз\n- Если данных недостаточно — пиши \"Данные не найдены\", НЕ выдумывай\n- Избегай общих слов и клише (\"динамично развивающаяся компания\", \"широкий спектр\")\n- Для business_scale используй табличный формат\n- Для collaboration_opportunities — обосновывай каждый формат конкретными фактами о компании\n\nСТРУКТУРА ССЫЛОК:\nВ поле references верни массив всех источников: [{\"number\": 1, \"text\": \"Название источника\", \"url\": \"https://...\"}]'))
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = now();

-- Insert sections schema
INSERT INTO public.app_settings (key, value)
VALUES ('ai_profile_sections', jsonb_build_object('sections', jsonb_build_array(
  jsonb_build_object('key', 'summary_short', 'title', 'Краткое описание', 'prompt', 'Напиши 2-3 предложения: основная деятельность, масштаб (выручка/сотрудники), уникальное ценностное предложение. Не повторяй информацию из других секций. Каждый факт — со ссылкой [N].'),
  jsonb_build_object('key', 'company_overview', 'title', 'Общие сведения о компании', 'prompt', 'История создания (год, основатели), миссия, основная деятельность, ключевые продукты/услуги. Укажи организационную структуру если известна. Факты со ссылками [N].'),
  jsonb_build_object('key', 'business_scale', 'title', 'Масштаб и показатели', 'prompt', 'ОБЯЗАТЕЛЬНО используй формат таблицы:\n| Показатель | Значение | Источник |\n|---|---|---|\n\nВключи: выручка (в динамике за 3+ лет если есть), количество сотрудников, география присутствия, доля рынка, рейтинги. Укажи структуру бизнеса по сегментам с процентами. Если точных данных нет — \"Данные не найдены\".'),
  jsonb_build_object('key', 'technology_focus', 'title', 'Технологический и продуктовый фокус', 'prompt', 'Перечисли конкретные технологии, платформы, продукты с названиями и версиями. Группируй по направлениям. Укажи технологический стек, используемые языки/фреймворки, собственные разработки vs лицензированные. Ссылки [N].'),
  jsonb_build_object('key', 'strategic_priorities', 'title', 'Стратегические направления', 'prompt', 'Выдели 3-5 ключевых стратегических направлений. Для каждого укажи: конкретные шаги, сроки, инвестиции если известны. Отдельно выдели направления, релевантные для академического партнёрства. Ссылки [N].'),
  jsonb_build_object('key', 'talent_needs', 'title', 'Кадровые потребности', 'prompt', 'Конкретные специальности и навыки (не общие \"IT-специалисты\"). Укажи: открытые вакансии если есть, программы стажировок, требования к уровню (junior/middle/senior), предпочтительные вузы-партнёры. Ссылки [N].'),
  jsonb_build_object('key', 'collaboration_opportunities', 'title', 'Потенциальный запрос к МИЭМ', 'prompt', 'Для каждого формата сотрудничества:\n1. Название формата\n2. Обоснование: ПОЧЕМУ это релевантно именно для этой компании (со ссылкой на конкретный факт из профайла)\n3. Конкретная тема/направление\n4. Потенциальное подразделение МИЭМ\n\nНе предлагай общие форматы без привязки к специфике компании.'),
  jsonb_build_object('key', 'current_relationship_with_miem', 'title', 'Текущее взаимодействие с МИЭМ', 'prompt', 'Если есть данные — опиши конкретно: проекты, мероприятия, контакты, даты. Если нет информации — напиши \"Данные о текущем взаимодействии с МИЭМ не найдены.\" Не выдумывай.'),
  jsonb_build_object('key', 'relationship_with_other_universities', 'title', 'Взаимодействие с другими университетами', 'prompt', 'Перечисли конкретные университеты-партнёры, форматы (лаборатории, кафедры, гранты, стипендии), даты начала. Укажи масштаб программ. Это важно для понимания конкурентного ландшафта. Ссылки [N].'),
  jsonb_build_object('key', 'recent_news_and_plans', 'title', 'Последние новости и планы', 'prompt', 'Только за последние 12-18 месяцев. Структурируй хронологически. Укажи: дата, суть новости, влияние на бизнес. Выдели новости, релевантные для академического сотрудничества. Ссылки [N].'),
  jsonb_build_object('key', 'key_events_and_touchpoints', 'title', 'Ключевые мероприятия', 'prompt', 'Конференции, хакатоны, митапы, дни открытых дверей, которые проводит или спонсирует компания. Укажи: название, периодичность, масштаб, тематику. Отметь мероприятия, где МИЭМ мог бы участвовать. Ссылки [N].'),
  jsonb_build_object('key', 'risks_and_constraints', 'title', 'Риски и ограничения', 'prompt', 'Конкретные риски для сотрудничества: санкции, закрытость, бюрократия, конкуренция с другими вузами, отраслевые ограничения. Для каждого риска укажи уровень (высокий/средний/низкий) и возможные митигации. Не пиши общие фразы.'),
  jsonb_build_object('key', 'recommended_next_steps', 'title', 'Рекомендуемые шаги', 'prompt', 'Пронумерованный список из 3-5 конкретных действий. Каждый шаг: что сделать, кто ответственный (МИЭМ/партнёр), ожидаемый срок, ожидаемый результат. Привяжи к конкретным фактам из профайла.')
)))
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = now();